class Solution {
public:
    int findLUSlength(string a, string b) {
        if (a == b) return -1;
        for (int i = 0; i < a.size(); i++) {
            string s = a.substr(0, i + 1);
            if (find(s.begin(), s.end(), b[0]) == s.end() && find(b.begin(), b.end(), s[0]) == b.end()) return s.size();
        }
        return -1;
    }
};
